import { Component, OnInit } from '@angular/core';
import { AuthService } from './services/auth.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
})
export class AppComponent implements OnInit {
  loading = true;

  constructor(private auth: AuthService) {}

  ngOnInit(): void {
    this.auth.loadCurrentUser().subscribe({
      next: () => (this.loading = false),
      error: () => {
        this.loading = false;
        // Si no está autenticado, redirigir al login de Symfony
        if (window.location.pathname.startsWith('/app')) {
          window.location.href = '/login';
        }
      },
    });
  }
}
<div *ngIf="loading" class="d-flex justify-content-center align-items-center" style="min-height:100vh">
  <div class="text-center">
    <div class="spinner-border text-primary mb-3" style="width:3rem;height:3rem" role="status"></div>
    <div class="text-muted small">Cargando SmartBooking…</div>
  </div>
</div>

<ng-container *ngIf="!loading">
  <app-navbar></app-navbar>
  <main class="sb-main-content">
    <div class="container-fluid">
      <router-outlet></router-outlet>
    </div>
  </main>
</ng-container>
